// Detect role-block violations:
// - Any Job A event inside Job B's canonical block (13:00-17:00)
// - Any Job B event inside Job A's canonical block (08:00-12:00)
// - Any event during declared focus/deep-work blocks
// - Any back-to-back events with <15min gap (breaks L-15 ramp-up discipline)

const JOBA_BLOCK_START = 8;   // 08:00
const JOBA_BLOCK_END = 12;    // 12:00
const JOBB_BLOCK_START = 13;  // 13:00
const JOBB_BLOCK_END = 17;    // 17:00
const MIN_GAP_MIN = 15;

const violations = [];
const events = items.map(i => i.json);

for (const event of events) {
  const start = new Date(event.start.dateTime || event.start.date);
  const end = new Date(event.end.dateTime || event.end.date);
  const hour = start.getHours();
  const calendarId = event.calendarId || 'unknown';

  // Check cross-role contamination
  const isJobA = calendarId.includes('joba') || event.summary?.toLowerCase().includes('[joba]');
  const isJobB = calendarId.includes('jobb') || event.summary?.toLowerCase().includes('[jobb]');

  if (isJobA && hour >= JOBB_BLOCK_START && hour < JOBB_BLOCK_END) {
    violations.push({
      type: 'cross-role-contamination',
      severity: 'high',
      event: event.summary,
      start: start.toISOString(),
      detail: 'Job A event in Job B block'
    });
  }
  if (isJobB && hour >= JOBA_BLOCK_START && hour < JOBA_BLOCK_END) {
    violations.push({
      type: 'cross-role-contamination',
      severity: 'high',
      event: event.summary,
      start: start.toISOString(),
      detail: 'Job B event in Job A block'
    });
  }

  // Check deep-work-block intrusion
  if (event.summary?.toLowerCase().includes('deep work') || event.summary?.toLowerCase().includes('focus block')) {
    continue; // This IS a focus block; not a violation
  }

  // Flag events during declared focus windows (08:30-11:30 and 13:30-16:30 are deep-work)
  if ((hour >= 8.5 && hour < 11.5) || (hour >= 13.5 && hour < 16.5)) {
    const minutes = start.getMinutes();
    const hourDec = hour + minutes / 60;
    if ((hourDec >= 8.5 && hourDec < 11.5) || (hourDec >= 13.5 && hourDec < 16.5)) {
      violations.push({
        type: 'deep-work-intrusion',
        severity: 'medium',
        event: event.summary,
        start: start.toISOString(),
        detail: 'Event scheduled during declared deep-work block'
      });
    }
  }
}

// Back-to-back check
const sortedEvents = events.sort((a, b) => 
  new Date(a.start.dateTime || a.start.date) - new Date(b.start.dateTime || b.start.date)
);
for (let i = 1; i < sortedEvents.length; i++) {
  const prevEnd = new Date(sortedEvents[i-1].end.dateTime || sortedEvents[i-1].end.date);
  const currStart = new Date(sortedEvents[i].start.dateTime || sortedEvents[i].start.date);
  const gapMin = (currStart - prevEnd) / (1000 * 60);
  if (gapMin > 0 && gapMin < MIN_GAP_MIN) {
    violations.push({
      type: 'back-to-back',
      severity: 'low',
      event: `${sortedEvents[i-1].summary} → ${sortedEvents[i].summary}`,
      start: currStart.toISOString(),
      detail: `${gapMin.toFixed(0)}min gap < ${MIN_GAP_MIN}min minimum`
    });
  }
}

return violations.map(v => ({ json: v }));
